INSERT INTO `actualite` (`id`, `titre`, `contenu`, `date_creation`) VALUES ('6', '23/04/2026 – Pièces jointes & calendrier', 'Fiche de visite : ajout des pièces jointes (upload, visualisation, téléchargement).\nListe des visites : icône trombone si des fichiers sont attachés au dossier.\nListe des visites : le filtre par année inclut désormais les dates prévues.\nCalendrier : correction des liens de navigation vers les fiches (déploiement sous-répertoire).', '2026-04-23 15:00:00');
INSERT INTO `actualite` (`id`, `titre`, `contenu`, `date_creation`) VALUES ('7', '23/04/2026 – Interface & navigation', 'Menu latéral : section Statistiques déplacée en bas.\nSuppression des modules Bâtiments et Intervenants.\nFormulaire de visite : suppression du champ « Type de visite ».', '2026-04-23 10:00:00');
INSERT INTO `actualite` (`id`, `titre`, `contenu`, `date_creation`) VALUES ('8', '22/04/2026 – Documents & statistiques', 'Tableau de bord : ajout de la rubrique « Documents et formulaires » (upload et téléchargement).\nStatistiques visites : clic sur une ligne pour accéder à la fiche de l\'agent.\nListe des visites : boutons Consulter, Modifier, Fiche de suivi dans les actions.', '2026-04-22 14:00:00');
INSERT INTO `actualite` (`id`, `titre`, `contenu`, `date_creation`) VALUES ('9', '21/04/2026 – Import dates & filtres', 'Import des dates de visites 2017–2026 depuis le fichier Excel.\nListe des visites : filtre par année, tri alphabétique par défaut sur le Nom.\nListe des visites : dates réalisées triées de la plus ancienne à la plus récente.\nListes RQTH et FIPHFP : suppression de la colonne Genre, tri alphabétique par défaut.', '2026-04-21 10:00:00');
INSERT INTO `actualite` (`id`, `titre`, `contenu`, `date_creation`) VALUES ('10', '20/04/2026 – Saisie & ergonomie', 'Formulaires visite/RQTH/FIPHFP : détection automatique du genre (M./Mme) selon le prénom saisi.\nTableau de services remplacé par la liste officielle des pôles/services.\nMessages flash : disparition automatique après 3 secondes.', '2026-04-20 10:00:00');
