INSERT INTO `inter` (`id`, `date`, `heure`, `service`, `panne_annonce`, `cout_matos`, `inter_effect`, `duree`, `intervenant`, `taux_intervenant`, `intervenant2`, `taux_intervenant2`, `intervenant3`, `taux_intervenant3`, `agent_visite`, `agent_rqth`, `pole_service_visite`, `pole_service_rqth`, `date_visite`, `observation`, `rqth_visite`, `restriction_visite`, `user_inter`, `urgence`, `type`, `recommandation_visite`, `limitation_visite`, `temps_partiel_visite`, `tpt1_du`, `tpt1_au`, `tpt2_du`, `tpt2_au`, `tpt3_du`, `tpt3_au`, `tpt4_du`, `tpt4_au`, `emploi_visite`, `emploi_rqth`, `prix1`, `etat_rqth`, `taux_total`, `par`) VALUES ('54', '27/01/2026', '0', '[POLE TECHNIQUE]', 'Entretien des EPI', '0.00', '27/01/26 :\nRéception de Davy Jeanson et Julien Lebas\nSollicitent des chaussures adaptées pour le poste en plantation\nNécessité d’installer une machine à laver à la ferme Ravel \n\n28/01/26 :\nEnvoi de mail à JM Tartare, L. Caron, D. Jeanson, S. Carlu et I. Calon\n\n29/01/2026 : Franck Cordier sollicite les mêmes chaussures pour lui ainsi que PM Lecompte et JL Hedin\nEn qualité d&rsquo;agent des espaces verts, souhaite savoir si la machine qu&rsquo;il devra utiliser sera celle des ST ou des EV.', '0.00', '', '0.00', '', '0.00', '', '0.00', '', '', '', '', '', 'L’objection du responsable de pôle est de mutualiser la machine avec les agents des services techniques et installer la machine à laver dans les bâtiments du services techniques.\n!!! Cela implique des allers retours entre les services, une survei', '', '', 'PÔLE TECHNIQUE', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '0.00', '', '0.00', 'Céline GOSSE');
